module RefModule(
    input clk,
    input reset,
    input signal,
    output reg zc_detected
);
    reg obf_prev_signal;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            obf_prev_signal <= 0;
            zc_detected <= 0;
        end else begin
            zc_detected <= (obf_prev_signal == 1'b0 && signal == 1'b1) || (obf_prev_signal == 1'b1 && signal == 1'b0);
            obf_prev_signal <= signal;
        end
    end
endmodule
